package com.pinova.service.impl;
import com.baomidou.mybatisplus.core.toolkit.*;import com.pinova.common.error.*;import com.pinova.mapper.*;import com.pinova.pojo.entity.*;import com.pinova.service.*;import com.pinova.service.command.*;import com.pinova.service.model.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.Instant;import java.util.*;
@Service public class AdminInventoryServiceImpl implements AdminInventoryService{
 private final WarehouseMapper warehouses;private final InventoryStockMapper stocks;private final InventoryLedgerMapper ledgers;private final InventoryReservationMapper reservations;private final AdminAuthorizationService auth;private final AdminOperationAuditService audit;
 public AdminInventoryServiceImpl(WarehouseMapper w,InventoryStockMapper s,InventoryLedgerMapper l,InventoryReservationMapper r,AdminAuthorizationService a,AdminOperationAuditService d){warehouses=w;stocks=s;ledgers=l;reservations=r;auth=a;audit=d;}
 @Override @Transactional(readOnly=true) public List<AdminWarehouseResult> listWarehouses(AuthenticatedAdminResult a){auth.requireSuperAdmin(a);return warehouses.selectList(Wrappers.lambdaQuery(Warehouse.class).orderByAsc(Warehouse::getShopId).orderByAsc(Warehouse::getWarehouseCode)).stream().map(AdminInventoryServiceImpl::warehouse).toList();}
 @Override @Transactional public AdminWarehouseResult saveWarehouse(SaveWarehouseCommand c){auth.requireSuperAdmin(c==null?null:c.admin());if(c.shopId()==null||c.shopId()<=0||blank(c.warehouseCode())||blank(c.name())||c.warehouseType()==null||(c.warehouseType()!=1&&c.warehouseType()!=2)||c.status()==null||(c.status()!=0&&c.status()!=1)||(c.id()!=null&&(c.version()==null||c.version()<0)))invalid("仓库参数无效");Instant now=Instant.now();if(c.id()==null){Warehouse w=new Warehouse();w.setId(IdWorker.getId());w.setShopId(c.shopId());w.setWarehouseCode(c.warehouseCode().trim().toUpperCase(Locale.ROOT));w.setName(c.name().trim());w.setWarehouseType(c.warehouseType());w.setStatus(c.status());w.setVersion(0);w.setDeleted(false);w.setCreatedAt(now);w.setCreatedBy(c.admin().id());w.setUpdatedAt(now);w.setUpdatedBy(c.admin().id());warehouses.insert(w);record(c.admin().id(),"CREATE_WAREHOUSE",w.getId(),null);return warehouse(w);}Warehouse w=warehouses.selectOne(Wrappers.lambdaQuery(Warehouse.class).eq(Warehouse::getId,c.id()).last("FOR UPDATE"));if(w==null)invalid("仓库不存在");List<Long> stockIds=stocks.selectList(Wrappers.lambdaQuery(InventoryStock.class).eq(InventoryStock::getWarehouseId,w.getId())).stream().map(InventoryStock::getId).toList();if(c.status()==0&&!stockIds.isEmpty()&&reservations.selectCount(Wrappers.lambdaQuery(InventoryReservation.class).in(InventoryReservation::getStockId,stockIds).eq(InventoryReservation::getStatus,(short)0))>0)invalid("仓库存在活动预占，不能停用");int n=warehouses.update(null,Wrappers.lambdaUpdate(Warehouse.class).eq(Warehouse::getId,w.getId()).eq(Warehouse::getVersion,c.version()).set(Warehouse::getName,c.name().trim()).set(Warehouse::getWarehouseType,c.warehouseType()).set(Warehouse::getStatus,c.status()).set(Warehouse::getUpdatedAt,now).set(Warehouse::getUpdatedBy,c.admin().id()).setSql("version = version + 1"));if(n!=1)conflict();record(c.admin().id(),"UPDATE_WAREHOUSE",w.getId(),null);return warehouse(warehouses.selectById(w.getId()));}
 @Override @Transactional(readOnly=true) public List<AdminStockResult> listStocks(AuthenticatedAdminResult a,Long warehouseId,Long skuId){auth.requireSuperAdmin(a);return stocks.selectList(Wrappers.lambdaQuery(InventoryStock.class).eq(warehouseId!=null,InventoryStock::getWarehouseId,warehouseId).eq(skuId!=null,InventoryStock::getSkuId,skuId).orderByAsc(InventoryStock::getWarehouseId).orderByAsc(InventoryStock::getSkuId)).stream().map(AdminInventoryServiceImpl::stock).toList();}
 @Override @Transactional public AdminStockResult adjust(AdjustInventoryCommand c){auth.requireSuperAdmin(c==null?null:c.admin());if(c.stockId()==null||c.stockId()<=0||blank(c.transactionNo())||c.transactionNo().length()>64||(!"DELTA".equals(c.mode())&&!"COUNT".equals(c.mode()))||c.quantity()==null||c.version()==null||c.version()<0||blank(c.reason()))invalid("库存调整参数无效");InventoryLedger replay=ledgers.selectOne(Wrappers.lambdaQuery(InventoryLedger.class).eq(InventoryLedger::getTransactionNo,c.transactionNo().trim()));if(replay!=null)return stock(stocks.selectById(replay.getStockId()));InventoryStock s=stocks.selectByIdForUpdate(c.stockId());if(s==null)invalid("库存记录不存在");long target;try{target="DELTA".equals(c.mode())?Math.addExact(s.getOnHandQuantity(),c.quantity()):c.quantity();}catch(ArithmeticException e){invalid("库存数量超出支持范围");return null;}if(target<s.getReservedQuantity()||target<0)invalid("调整后现货不能低于预占数量");long delta=target-s.getOnHandQuantity();if(delta==0)invalid("库存数量没有变化");Instant now=Instant.now();int n=stocks.update(null,Wrappers.lambdaUpdate(InventoryStock.class).eq(InventoryStock::getId,s.getId()).eq(InventoryStock::getVersion,c.version()).set(InventoryStock::getOnHandQuantity,target).set(InventoryStock::getUpdatedAt,now).set(InventoryStock::getUpdatedBy,c.admin().id()).setSql("version = version + 1"));if(n!=1)conflict();InventoryLedger l=new InventoryLedger();l.setId(IdWorker.getId());l.setTransactionNo(c.transactionNo().trim());l.setStockId(s.getId());l.setChangeType((short)("COUNT".equals(c.mode())?(delta>0?5:6):(delta>0?1:2)));l.setOnHandDelta(delta);l.setReservedDelta(0L);l.setOnHandAfter(target);l.setReservedAfter(s.getReservedQuantity());l.setReferenceType("ADMIN_ADJUSTMENT");l.setReferenceId(c.admin().id());l.setRemark(c.reason().trim());l.setOccurredAt(now);l.setCreatedAt(now);l.setCreatedBy(c.admin().id());l.setUpdatedAt(now);l.setUpdatedBy(c.admin().id());ledgers.insert(l);record(c.admin().id(),"ADJUST_STOCK",s.getId(),c.reason());return stock(stocks.selectById(s.getId()));}
 private void record(Long op,String action,Long id,String reason){audit.record(new RecordAdminAuditCommand(op,"INVENTORY",action,"INVENTORY",String.valueOf(id),null,reason,null,null));}private static AdminWarehouseResult warehouse(Warehouse w){return new AdminWarehouseResult(w.getId(),w.getShopId(),w.getWarehouseCode(),w.getName(),w.getWarehouseType(),w.getStatus(),w.getVersion());}private static AdminStockResult stock(InventoryStock s){return new AdminStockResult(s.getId(),s.getWarehouseId(),s.getSkuId(),s.getOnHandQuantity(),s.getReservedQuantity(),s.getOnHandQuantity()-s.getReservedQuantity(),s.getVersion());}private static boolean blank(String v){return v==null||v.isBlank();}private static void invalid(String m){throw new BusinessException(CommonErrorCode.INVALID_REQUEST,m);}private static void conflict(){throw new BusinessException(CommonErrorCode.INVALID_REQUEST,"库存或仓库已变化，请刷新后重试");}
}
